package main

import (
	"sort"
)

const MOD = 1000000007

func solve(points [][]int64) int64 {
	yToXs := make(map[int64][]int64)
	for _, point := range points {
		x, y := point[0], point[1]
		yToXs[y] = append(yToXs[y], x)
	}

	// Sort the x-coordinates for each y
	for y := range yToXs {
		sort.Slice(yToXs[y], func(i, j int) bool {
			return yToXs[y][i] < yToXs[y][j]
		})
	}

	// Collect counts of points for each y where count >= 2
	var countYs []int64
	for _, xs := range yToXs {
		if len(xs) >= 2 {
			countYs = append(countYs, int64(len(xs)))
		}
	}

	if len(countYs) < 2 {
		return 0
	}

	// Precompute prefix sums of C(k, 2)
	prefix := make([]int64, len(countYs)+1)
	for i := 0; i < len(countYs); i++ {
		c := countYs[i]
		prefix[i+1] = prefix[i] + c*(c-1)/2
	}

	totalC := prefix[len(countYs)]
	var res int64
	for i := 0; i < len(countYs); i++ {
		ci := countYs[i]
		current := ci * (ci - 1) / 2
		remaining := totalC - prefix[i+1]
		res += current * remaining
		res %= MOD
	}

	return res
}
